// Parse the Kafka message
const msg = $input.first().json;
const order = typeof msg.value === 'string' ? JSON.parse(msg.value) : msg.value;
return [{ json: order }];

const order = $('Parse: Kafka Message').first().json;
const inventory = $input.all().map(i => i.json);

const allocations = [];
const backorders = [];

for (const item of order.items) {
  let remaining = item.quantity;
  const itemAllocs = [];

  // Sort warehouses: closest/highest stock first (simplified: highest qty first)
  const warehouses = inventory
    .filter(r => r.product_id === item.product_id)
    .sort((a, b) => b.available_qty - a.available_qty);

  for (const wh of warehouses) {
    if (remaining <= 0) break;
    const take = Math.min(remaining, wh.available_qty);
    itemAllocs.push({
      product_id: item.product_id,
      warehouse_id: wh.warehouse_id,
      allocated_qty: take
    });
    remaining -= take;
  }

  if (remaining > 0) {
    backorders.push({
      product_id: item.product_id,
      quantity_required: item.quantity,
      quantity_available: item.quantity - remaining,
      quantity_backorder: remaining
    });
  }

  allocations.push(...itemAllocs);
}

const fulfillmentType = backorders.length === 0
  ? 'FULL'
  : allocations.length > 0
    ? 'PARTIAL'
    : 'BACKORDER';

return [{
  json: {
    ...order,
    allocations,
    backorders,
    fulfillment_type: fulfillmentType,
    status: fulfillmentType === 'BACKORDER' ? 'BACKORDERED' : 'ALLOCATED',
    updated_at: new Date().toISOString()
  }
}];

// Log backorder notification
const order = $input.first().json;
console.log(`Backorder triggered for ${order.order_id}:`, order.backorders);
return [{ json: order }];
